[GQL-OP add_item]
[GQL-VARS add_item] {"configurationSections": [{"sectionId": "{{SECTION_RAM_ID}}", "type": "Product", "option": {"productId": "{{OPT_RAM_BASE_ID}}", "quantity": 1}}, {"sectionId": "{{SECTION_STORAGE_ID}}", "type": "Product", "option": {"productId": "{{OPT_STORAGE_BASE_ID}}", "quantity": 1}}]}
  mutation AddItem($configurationSections: [ConfigurationSectionInput]) {
    addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "@td(CFG_LAPTOP.id)" quantity: 1 configurationSections: $configurationSections }) {
      id itemsCount items { id productId configurationItems { id sectionId productId } }
    }
  }
[GQL-EXEC add_item]
[GQL-CAPTURE add_item.data.addItem.items.0.id → LINE_ITEM_ID]
[GQL-OP add_section]
[GQL-VARS add_section] {"configurationSection": {"sectionId": "{{SECTION_RAM_ID}}", "type": "Product", "option": {"productId": "{{OPT_RAM_UPGRADE_ID}}", "quantity": 1}}}
  mutation AddConfigurationItem($configurationSection: ConfigurationSectionInput!) {
    addConfigurationItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" lineItemId: "{{LINE_ITEM_ID}}" configurationSection: $configurationSection }) {
      id items { id configurationItems { id sectionId type productId } }
    }
  }
[GQL-EXEC add_section]
[GQL-OP read_back]
  query { configurationItems(storeId: "{{STORE_ID}}" currencyCode: "USD" lineItemId: "{{LINE_ITEM_ID}}" userId: "{{USER_ID}}") { configurationItems { id sectionId type productId } } }
[GQL-EXEC read_back]
[GQL-OP cleanup_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_post]

